import React, { useState } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const SignupContainer = styled.div`
  max-width: 500px;
  margin: 4rem auto;
  padding: 3rem;
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(24px);
  box-shadow: ${props => props.theme.shadows.card};
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(56, 189, 248, 0.3), transparent);
  }
`;

const Title = styled(motion.h1)`
  font-size: 2.5rem;
  margin-bottom: 0.5rem;
  text-align: center;
  font-weight: 900;
  letter-spacing: -2px;
  background: ${props => props.theme.colors.accentPrimary};
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
`;

const Subtitle = styled.p`
  text-align: center;
  color: ${props => props.theme.colors.textSecondary};
  margin-bottom: 2.5rem;
  font-size: 0.95rem;
`;

const SignupForm = styled(motion.form)`
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
`;

const InputGroup = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
`;

const Label = styled.label`
  font-size: 0.8rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: ${props => props.theme.colors.textSecondary};
  margin-left: 4px;
`;

const Input = styled.input`
  width: 100%;
  padding: 1rem 1.25rem;
  background: ${props => props.theme.colors.glass};
  border: 1px solid ${props => props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.medium};
  color: ${props => props.theme.colors.textPrimary};
  font-size: 1rem;
  transition: ${props => props.theme.transitions.default};

  &:focus {
    outline: none;
    border-color: ${props => props.theme.colors.info}50;
    background: rgba(255, 255, 255, 0.05);
    box-shadow: 0 0 0 4px ${props => props.theme.colors.info}10;
  }
`;

const Button = styled(motion.button)`
  width: 100%;
  padding: 1rem;
  background: ${props => props.theme.colors.accentPrimary};
  color: #fff;
  border: none;
  border-radius: ${props => props.theme.borderRadius.medium};
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  margin-top: 1rem;
  transition: ${props => props.theme.transitions.default};
  box-shadow: ${props => props.theme.shadows.glow};

  &:hover {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
`;

const SwitchText = styled.p`
  text-align: center;
  margin-top: 2rem;
  color: ${props => props.theme.colors.textSecondary};
  font-size: 0.9rem;

  span {
    color: ${props => props.theme.colors.info};
    cursor: pointer;
    font-weight: 700;

    &:hover {
      text-decoration: underline;
    }
  }
`;

const Message = styled(motion.div)<{ type: 'success' | 'error' }>`
  background: ${props => props.type === 'success' ? props.theme.colors.success + '15' : props.theme.colors.danger + '15'};
  border: 1px solid ${props => props.type === 'success' ? props.theme.colors.success + '30' : props.theme.colors.danger + '30'};
  border-radius: 12px;
  padding: 1rem;
  text-align: center;
  color: ${props => props.type === 'success' ? props.theme.colors.success : props.theme.colors.danger};
  margin-top: 1.5rem;
  font-size: 0.9rem;
  font-weight: 600;
`;

const Signup: React.FC = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    password: ''
  });
  const navigate = useNavigate();
  const { register, login, user } = useAuth();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    try {
      if (isLogin) {
        await login({
          username: formData.email,
          password: formData.password
        });
      } else {
        await register({
          username: formData.email,
          email: formData.email,
          phone: formData.phone,
          password: formData.password,
          password_confirm: formData.password,
          first_name: formData.name
        });
      }

      setSuccess(true);
      setTimeout(() => {
        navigate('/');
      }, 1500);
    } catch (err: any) {
      if (err && err.errors) {
        const messages = Object.values(err.errors).flat() as any[];
        const first = messages.length > 0 ? messages[0] : '';
        setError(typeof first === 'string' ? first : String(first) || 'Authentication failed');
      } else if (err && err.message) {
        setError(String(err.message));
      } else {
        setError(isLogin ? 'Login failed' : 'Registration failed');
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  if (user && success) {
    return (
      <SignupContainer>
        <Title>Welcome to Zeus</Title>
        <Subtitle>Redirecting you to the command center...</Subtitle>
        <Message type="success">
          Authentication Successful! ⚡️<br/>
          Secure connection established.
        </Message>
      </SignupContainer>
    );
  }

  return (
    <SignupContainer>
      <Title>{isLogin ? 'Welcome Back' : 'Join Zeus'}</Title>
      <Subtitle>
        {isLogin ? 'Access your institutional dashboard' : 'Start your journey with advanced market intelligence'}
      </Subtitle>

      <SignupForm onSubmit={handleSubmit}>
        {!isLogin && (
          <>
            <InputGroup>
              <Label>Full Name</Label>
              <Input
                type="text"
                name="name"
                placeholder="Enter your name"
                value={formData.name}
                onChange={handleInputChange}
                required
              />
            </InputGroup>
            <InputGroup>
              <Label>Phone Number</Label>
              <Input
                type="tel"
                name="phone"
                placeholder="+1 (555) 000-0000"
                value={formData.phone}
                onChange={handleInputChange}
                required
              />
            </InputGroup>
          </>
        )}

        <InputGroup>
          <Label>Email Address</Label>
          <Input
            type="email"
            name="email"
            placeholder="name@company.com"
            value={formData.email}
            onChange={handleInputChange}
            required
          />
        </InputGroup>

        <InputGroup>
          <Label>Password</Label>
          <Input
            type="password"
            name="password"
            placeholder="••••••••"
            value={formData.password}
            onChange={handleInputChange}
            required
          />
        </InputGroup>

        <Button
          type="submit"
          disabled={isSubmitting}
          whileHover={{ scale: 1.01 }}
          whileTap={{ scale: 0.99 }}
        >
          {isSubmitting ? 'Connecting...' : (isLogin ? 'Sign In' : 'Create Account')}
        </Button>
      </SignupForm>

      <AnimatePresence>
        {error && (
          <Message 
            type="error"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
          >
            {error}
          </Message>
        )}
      </AnimatePresence>

      <SwitchText>
        {isLogin ? "Don't have an account?" : "Already have an account?"}{' '}
        <span onClick={() => { setIsLogin(!isLogin); setError(''); }}>
          {isLogin ? 'Register Now' : 'Sign In'}
        </span>
      </SwitchText>
    </SignupContainer>
  );
};

export default Signup;
